import { Drawer as DrawerPrimitive } from '@base-ui/react/drawer';
import { clsx } from 'clsx';
import { createContext, useContext, useEffect, useState, type ComponentProps } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import { CloseButton } from '../close-button';
import styles from './Drawer.module.css';

const DEFAULT_CLOSE_BUTTON_LABEL = 'Close drawer';
const DrawerModeContext = createContext<DrawerPrimitive.Root.Props['modal']>(true);

function useMountReady(disableInitialAnimation: boolean) {
  const [mountReady, setMountReady] = useState(!disableInitialAnimation);

  useEffect(() => {
    if (!disableInitialAnimation) {
      setMountReady(true);
      return;
    }

    setMountReady(false);
    let frame = window.requestAnimationFrame(() => {
      setMountReady(true);
    });

    return () => {
      window.cancelAnimationFrame(frame);
    };
  }, [disableInitialAnimation]);

  return mountReady;
}

function Drawer<Payload = unknown>({
  modal = true,
  ...props
}: DrawerPrimitive.Root.Props<Payload>) {
  return (
    <DrawerModeContext.Provider value={modal}>
      <DrawerPrimitive.Root modal={modal} {...props} />
    </DrawerModeContext.Provider>
  );
}

const DrawerProvider = DrawerPrimitive.Provider;
const createDrawerHandle = DrawerPrimitive.createHandle;

function DrawerIndent({ className, ...props }: DrawerPrimitive.Indent.Props) {
  return (
    <DrawerPrimitive.Indent
      data-slot="drawer-indent"
      className={mergeClassName(className, styles.indent)}
      {...props}
    />
  );
}

function DrawerIndentBackground({ className, ...props }: DrawerPrimitive.IndentBackground.Props) {
  return (
    <DrawerPrimitive.IndentBackground
      data-slot="drawer-indent-background"
      className={mergeClassName(className, styles.indentBackground)}
      {...props}
    />
  );
}

function DrawerTrigger({ className, render, ...props }: DrawerPrimitive.Trigger.Props) {
  return (
    <DrawerPrimitive.Trigger
      data-slot="drawer-trigger"
      render={render}
      className={render ? className : mergeClassName(className, styles.trigger)}
      {...props}
    />
  );
}

function DrawerSwipeArea({ className, ...props }: DrawerPrimitive.SwipeArea.Props) {
  return (
    <DrawerPrimitive.SwipeArea
      data-slot="drawer-swipe-area"
      className={mergeClassName(className, styles.swipeArea)}
      {...props}
    />
  );
}

function DrawerPortal({ className, ...props }: DrawerPrimitive.Portal.Props) {
  return <DrawerPrimitive.Portal data-slot="drawer-portal" className={className} {...props} />;
}

function DrawerBackdrop({ className, ...props }: DrawerPrimitive.Backdrop.Props) {
  return (
    <DrawerPrimitive.Backdrop
      data-slot="drawer-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function DrawerViewport({ className, ...props }: DrawerPrimitive.Viewport.Props) {
  return (
    <DrawerPrimitive.Viewport
      data-slot="drawer-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function DrawerPopup({ className, ...props }: DrawerPrimitive.Popup.Props) {
  return (
    <DrawerPrimitive.Popup
      data-slot="drawer-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function DrawerHandle({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-handle" className={clsx(styles.handle, className)} {...props} />;
}

function DrawerContentInner({ className, ...props }: DrawerPrimitive.Content.Props) {
  return (
    <DrawerPrimitive.Content
      data-slot="drawer-content"
      className={mergeClassName(className, styles.content)}
      {...props}
    />
  );
}

function DrawerTitle({ className, ...props }: DrawerPrimitive.Title.Props) {
  return (
    <DrawerPrimitive.Title
      data-slot="drawer-title"
      className={mergeClassName(className, styles.title)}
      {...props}
    />
  );
}

function DrawerDescription({ className, ...props }: DrawerPrimitive.Description.Props) {
  return (
    <DrawerPrimitive.Description
      data-slot="drawer-description"
      className={mergeClassName(className, styles.description)}
      {...props}
    />
  );
}

function DrawerClose({ className, ...props }: DrawerPrimitive.Close.Props) {
  return (
    <DrawerPrimitive.Close
      data-slot="drawer-close"
      className={mergeClassName(className, styles.close)}
      {...props}
    />
  );
}

function DrawerCloseIcon({
  className,
  children,
  'aria-label': ariaLabel = DEFAULT_CLOSE_BUTTON_LABEL,
  render,
  ...props
}: DrawerPrimitive.Close.Props) {
  return (
    <DrawerPrimitive.Close
      data-slot="drawer-close-icon"
      render={render ?? <CloseButton aria-label={ariaLabel}>{children}</CloseButton>}
      className={mergeClassName(className, styles.closeIcon)}
      {...props}
    />
  );
}

function DrawerHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-header" className={clsx(styles.header, className)} {...props} />;
}

function DrawerBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-body" className={clsx(styles.body, className)} {...props} />;
}

function DrawerFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-footer" className={clsx(styles.footer, className)} {...props} />;
}

function DrawerContent({
  snapLayout = false,
  disableInitialAnimation = false,
  variant = 'default',
  className,
  children,
  ...props
}: DrawerPrimitive.Popup.Props & {
  snapLayout?: boolean;
  disableInitialAnimation?: boolean;
  variant?: 'default' | 'island';
}) {
  const modal = useContext(DrawerModeContext);
  const mountReady = useMountReady(disableInitialAnimation);
  const blocksOutsidePointerInteraction = modal === true;
  const viewportClassName = mergeClassName(
    blocksOutsidePointerInteraction ? undefined : styles.viewportNonModal,
    variant === 'island' ? styles.viewportIsland : undefined,
  );

  return (
    <DrawerPortal>
      {blocksOutsidePointerInteraction ? <DrawerBackdrop /> : null}
      <DrawerViewport className={viewportClassName}>
        <DrawerPopup
          data-snap-layout={snapLayout ? '' : undefined}
          data-disable-initial-animation={disableInitialAnimation ? 'true' : undefined}
          data-mount-ready={mountReady ? 'true' : 'false'}
          data-variant={variant}
          className={className}
          {...props}
        >
          <DrawerHandle />
          <DrawerContentInner>{children}</DrawerContentInner>
        </DrawerPopup>
      </DrawerViewport>
    </DrawerPortal>
  );
}

export {
  Drawer,
  DrawerProvider,
  createDrawerHandle,
  DrawerIndent,
  DrawerIndentBackground,
  DrawerTrigger,
  DrawerSwipeArea,
  DrawerPortal,
  DrawerBackdrop,
  DrawerViewport,
  DrawerPopup,
  DrawerHandle,
  DrawerContentInner,
  DrawerTitle,
  DrawerDescription,
  DrawerClose,
  DrawerCloseIcon,
  DrawerHeader,
  DrawerBody,
  DrawerFooter,
  DrawerContent,
};

@layer ui.components {
  .indentBackground {
    position: absolute;
    inset: 0;
    background: var(--drawer-indent-background-bg, var(--color-foreground));
    opacity: var(--drawer-indent-background-opacity, 0);
    transition: opacity var(--drawer-indent-transition, var(--transition-spring));
    pointer-events: none;

    &[data-active] {
      opacity: var(--drawer-indent-background-opacity-active, 1);
    }
  }

  .indent {
    position: relative;
    transition:
      transform var(--drawer-indent-transition, var(--transition-spring)),
      border-radius var(--drawer-indent-radius-transition, var(--transition-spring));
    transform: translateY(0) scale(1);
    transform-origin: center top;

    &[data-active] {
      border-top-left-radius: var(--drawer-indent-radius-active, var(--radius-lg));
      border-top-right-radius: var(--drawer-indent-radius-active, var(--radius-lg));
      transform: translateY(var(--drawer-indent-translate-y-active, var(--spacing-2)))
        scale(var(--drawer-indent-scale-active, 0.98));
    }
  }

  .trigger,
  .close {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--drawer-control-height, var(--size-lg));
    margin: 0;
    padding: var(--drawer-control-padding-y, 0.5rem) var(--drawer-control-padding-x, 0.875rem);
    border: var(--drawer-control-border-width, var(--border-width-sm)) solid
      var(--drawer-control-border-color, var(--color-border));
    border-radius: var(--drawer-control-radius, var(--radius-md));
    background-color: var(--drawer-control-bg, var(--color-background));
    color: var(--drawer-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--drawer-control-font-size, var(--text-md));
    line-height: var(--drawer-control-line-height, var(--line-height-text-md));
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--drawer-control-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(
          --drawer-focus-ring-width,
          var(--drawer-control-border-width, var(--border-width-sm))
        )
        solid var(--drawer-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(--drawer-focus-ring-width, var(--drawer-control-border-width, var(--border-width-sm))) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--opacity-disabled);
    }
  }

  .swipeArea {
    position: fixed;
    z-index: var(--z-modal);
    touch-action: none;

    &[data-disabled] {
      pointer-events: none;
    }

    &[data-swipe-direction='up'] {
      right: 0;
      bottom: 0;
      left: 0;
      height: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-swipe-direction='down'] {
      top: 0;
      right: 0;
      left: 0;
      height: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-swipe-direction='left'] {
      top: 0;
      right: 0;
      bottom: 0;
      width: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-swipe-direction='right'] {
      top: 0;
      bottom: 0;
      left: 0;
      width: var(--drawer-swipe-area-size, var(--spacing-10));
    }
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--drawer-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--drawer-backdrop-blur, 4px)));
    opacity: calc(1 - var(--drawer-swipe-progress, 0));
    pointer-events: var(--drawer-backdrop-pointer-events, auto);
    transition:
      opacity var(--drawer-backdrop-transition, var(--transition-spring)),
      backdrop-filter var(--drawer-backdrop-transition, var(--transition-spring));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      backdrop-filter: none;
    }

    &[data-swiping] {
      transition-duration: 0s;
    }

    &[data-ending-style] {
      transition-duration: calc(var(--drawer-swipe-strength, 1) * var(--duration-slower));
    }
  }

  .viewport {
    position: fixed;
    z-index: var(--z-modal);
    top: var(--drawer-viewport-top, 0);
    right: var(--drawer-viewport-right, 0);
    bottom: var(--drawer-viewport-bottom, 0);
    left: var(--drawer-viewport-left, 0);
    display: flex;
    align-items: flex-end;
    justify-content: center;
    padding: var(--drawer-viewport-padding, 0px);
    pointer-events: var(--drawer-viewport-pointer-events, auto);
    overscroll-behavior: contain;

    &:has(.popup[data-swipe-direction='up']) {
      align-items: flex-start;
      justify-content: center;
    }

    &:has(.popup[data-swipe-direction='left']) {
      align-items: center;
      justify-content: flex-start;
    }

    &:has(.popup[data-swipe-direction='right']) {
      align-items: center;
      justify-content: flex-end;
    }
  }

  .viewportNonModal {
    pointer-events: none;
  }

  .viewportIsland {
    --drawer-viewport-padding: var(--drawer-island-padding, var(--spacing-4));
  }

  .popup {
    --drawer-bleed: var(--drawer-bleed-size, 3rem);
    box-sizing: border-box;
    position: relative;
    border: var(--border-width-sm) solid var(--drawer-border-color, var(--color-border));
    background: var(--drawer-bg, var(--color-popover));
    color: var(--drawer-color, var(--color-popover-foreground));
    box-shadow: var(--drawer-shadow, var(--shadow-lg));
    outline: none;
    display: flex;
    flex-direction: column;
    touch-action: auto;
    overflow: hidden;
    overscroll-behavior: contain;
    pointer-events: var(--drawer-popup-pointer-events, auto);
    transition: transform var(--drawer-transition, var(--transition-spring));

    &[data-swiping] {
      user-select: none;
    }

    &[data-swipe-direction='down'] {
      width: min(var(--drawer-width, 100%), 100vw);
      max-height: calc(var(--drawer-max-height, 80vh) + var(--drawer-bleed));
      min-height: 0;
      margin-bottom: calc(-1 * var(--drawer-bleed));
      padding: var(--drawer-padding-y, var(--spacing-4)) var(--drawer-padding-x, var(--spacing-6))
        calc(
          var(--drawer-padding-y, var(--spacing-4)) + env(safe-area-inset-bottom, 0px) +
            var(--drawer-bleed)
        );
      padding-top: calc(
        var(--drawer-padding-y, var(--spacing-4)) + var(--drawer-handle-offset, var(--spacing-3)) +
          var(--drawer-handle-height, 0.25rem)
      );
      border-radius: var(--drawer-radius, var(--radius-xl)) var(--drawer-radius, var(--radius-xl)) 0
        0;
      transform: translateY(
        calc(var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px))
      );

      &[data-starting-style],
      &[data-ending-style] {
        transform: translateY(calc(100% - var(--drawer-bleed) + 2px));
      }
    }

    &[data-swipe-direction='up'] {
      width: min(var(--drawer-width, 100%), 100vw);
      max-height: calc(var(--drawer-max-height, 80vh) + var(--drawer-bleed));
      min-height: 0;
      margin-top: calc(-1 * var(--drawer-bleed));
      padding: calc(
          var(--drawer-padding-y, var(--spacing-4)) + env(safe-area-inset-top, 0px) +
            var(--drawer-bleed)
        )
        var(--drawer-padding-x, var(--spacing-6)) var(--drawer-padding-y, var(--spacing-4));
      padding-bottom: calc(
        var(--drawer-padding-y, var(--spacing-4)) + var(--drawer-handle-offset, var(--spacing-3)) +
          var(--drawer-handle-height, 0.25rem)
      );
      border-radius: 0 0 var(--drawer-radius, var(--radius-xl))
        var(--drawer-radius, var(--radius-xl));
      transform: translateY(
        calc(var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px))
      );

      &[data-starting-style],
      &[data-ending-style] {
        transform: translateY(calc(-100% + var(--drawer-bleed) - 2px));
      }
    }

    &[data-swipe-direction='right'] {
      width: calc(var(--drawer-side-width, 22rem) + var(--drawer-bleed));
      max-width: calc(100vw - 3rem + var(--drawer-bleed));
      height: var(--drawer-side-height, 100%);
      max-height: var(--drawer-side-max-height, 100%);
      min-height: 0;
      margin-right: calc(-1 * var(--drawer-bleed));
      padding: var(--drawer-padding-y, var(--spacing-6))
        calc(var(--drawer-padding-x, var(--spacing-6)) + var(--drawer-bleed))
        var(--drawer-padding-y, var(--spacing-6)) var(--drawer-padding-x, var(--spacing-6));
      border-radius: var(--drawer-radius, var(--radius-xl)) 0 0
        var(--drawer-radius, var(--radius-xl));
      transform: translateX(var(--drawer-swipe-movement-x, 0px));

      &[data-starting-style],
      &[data-ending-style] {
        transform: translateX(
          calc(100% - var(--drawer-bleed) + var(--drawer-viewport-padding, 0px) + 2px)
        );
      }
    }

    &[data-swipe-direction='left'] {
      width: calc(var(--drawer-side-width, 22rem) + var(--drawer-bleed));
      max-width: calc(100vw - 3rem + var(--drawer-bleed));
      height: var(--drawer-side-height, 100%);
      max-height: var(--drawer-side-max-height, 100%);
      min-height: 0;
      margin-left: calc(-1 * var(--drawer-bleed));
      padding: var(--drawer-padding-y, var(--spacing-6)) var(--drawer-padding-x, var(--spacing-6))
        var(--drawer-padding-y, var(--spacing-6))
        calc(var(--drawer-padding-x, var(--spacing-6)) + var(--drawer-bleed));
      border-radius: 0 var(--drawer-radius, var(--radius-xl)) var(--drawer-radius, var(--radius-xl))
        0;
      transform: translateX(var(--drawer-swipe-movement-x, 0px));

      &[data-starting-style],
      &[data-ending-style] {
        transform: translateX(
          calc(-100% + var(--drawer-bleed) - var(--drawer-viewport-padding, 0px) - 2px)
        );
      }
    }

    &[data-ending-style] {
      transition-duration: calc(var(--drawer-swipe-strength, 1) * var(--duration-slower));
    }

    &[data-disable-initial-animation='true'][data-mount-ready='false'] {
      transition: none;

      &[data-starting-style][data-swipe-direction='down'],
      &[data-starting-style][data-swipe-direction='up'] {
        transform: translateY(
          calc(var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px))
        );
      }

      &[data-starting-style][data-swipe-direction='left'],
      &[data-starting-style][data-swipe-direction='right'] {
        transform: translateX(var(--drawer-swipe-movement-x, 0px));
      }
    }

    &[data-variant='island'] {
      --drawer-bleed: 0px;
    }

    &[data-variant='island'][data-snap-layout] {
      --drawer-snap-tail-size: 0px;
    }

    &[data-variant='island'][data-swipe-direction='down'],
    &[data-variant='island'][data-swipe-direction='up'],
    &[data-variant='island'][data-swipe-direction='left'],
    &[data-variant='island'][data-swipe-direction='right'] {
      border-radius: var(--drawer-radius, var(--radius-xl));
    }

    &[data-snap-layout][data-swipe-direction='down'] {
      --drawer-bleed: 0px;
      --drawer-snap-tail-size: var(--drawer-bleed-size, 3rem);
      --drawer-snap-visible-height: calc(
        100% -
          max(0px, calc(var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px)))
      );

      height: var(--drawer-max-height, 100dvh);
      max-height: var(--drawer-max-height, 100dvh);
      margin-bottom: 0;
      padding-bottom: calc(
        var(--drawer-padding-y, var(--spacing-4)) + env(safe-area-inset-bottom, 0px)
      );
      overflow: visible;
      touch-action: none;

      &::after {
        position: absolute;
        top: 100%;
        right: 0;
        left: 0;
        height: var(--drawer-snap-tail-size);
        background: var(--drawer-bg, var(--color-popover));
        content: '';
        pointer-events: none;
      }
    }

    &[data-snap-layout][data-swipe-direction='up'] {
      --drawer-bleed: 0px;
      --drawer-snap-tail-size: var(--drawer-bleed-size, 3rem);
      --drawer-snap-visible-height: calc(
        100% -
          max(
            0px,
            calc(-1 * (var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px)))
          )
      );

      height: var(--drawer-max-height, 100dvh);
      max-height: var(--drawer-max-height, 100dvh);
      margin-top: 0;
      padding-top: calc(var(--drawer-padding-y, var(--spacing-4)) + env(safe-area-inset-top, 0px));
      overflow: visible;
      touch-action: none;

      &::after {
        position: absolute;
        right: 0;
        bottom: 100%;
        left: 0;
        height: var(--drawer-snap-tail-size);
        background: var(--drawer-bg, var(--color-popover));
        content: '';
        pointer-events: none;
      }
    }

    &[data-nested-drawer-open][data-swipe-direction='down'] {
      height: calc(
        max(
            0px,
            calc(
              var(--drawer-frontmost-height, var(--drawer-height)) -
                var(--drawer-nested-peek, 2.75rem)
            )
          ) +
          var(--drawer-bleed)
      );
      overflow: hidden;
      transform: translateY(
          calc(
            var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px) -
              var(--drawer-nested-peek, 2.75rem) * var(--nested-drawers, 1)
          )
        )
        scale(calc(1 - var(--drawer-nested-scale-step, 0.06) * var(--nested-drawers, 0)));
      transform-origin: bottom center;
    }

    &[data-nested-drawer-open][data-swipe-direction='up'] {
      height: calc(
        max(
            0px,
            calc(
              var(--drawer-frontmost-height, var(--drawer-height)) -
                var(--drawer-nested-peek, 2.75rem)
            )
          ) +
          var(--drawer-bleed)
      );
      overflow: hidden;
      transform: translateY(
          calc(
            var(--drawer-snap-point-offset, 0px) + var(--drawer-swipe-movement-y, 0px) +
              var(--drawer-nested-peek, 2.75rem) * var(--nested-drawers, 1)
          )
        )
        scale(calc(1 - var(--drawer-nested-scale-step, 0.06) * var(--nested-drawers, 0)));
      transform-origin: top center;
    }
  }

  .handle {
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    width: var(--drawer-handle-width, 3rem);
    height: var(--drawer-handle-height, 0.25rem);
    border-radius: var(--drawer-handle-radius, var(--radius-full));
    background: var(--drawer-handle-bg, var(--color-muted-foreground));
    opacity: var(--drawer-handle-opacity, 0.45);
    flex: 0 0 auto;

    .popup[data-swipe-direction='down'] & {
      top: var(--drawer-handle-offset, var(--spacing-3));
    }

    .popup[data-swipe-direction='up'] & {
      bottom: var(--drawer-handle-offset, var(--spacing-3));
    }

    .popup[data-swipe-direction='left'] &,
    .popup[data-swipe-direction='right'] & {
      display: none;
    }
  }

  .content {
    display: flex;
    min-height: 0;
    flex: 1;
    flex-direction: column;
    overflow: hidden;
    width: 100%;

    .popup[data-snap-layout] & {
      height: var(--drawer-snap-visible-height, 100%);
      max-height: var(--drawer-snap-visible-height, 100%);
      flex: 0 1 auto;
      flex-basis: var(--drawer-snap-visible-height, 100%);
      transition:
        height var(--drawer-transition, var(--transition-spring)),
        max-height var(--drawer-transition, var(--transition-spring)),
        flex-basis var(--drawer-transition, var(--transition-spring));
    }

    .popup[data-snap-layout][data-swiping] & {
      transition: none;
    }
  }

  .header {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    align-items: start;
    gap: var(--drawer-header-gap, var(--spacing-1));

    & > [data-slot='drawer-title'] {
      grid-column: 1;
    }

    & > [data-slot='drawer-close'],
    & > [data-slot='drawer-close-icon'] {
      grid-column: 2;
      justify-self: end;
    }

    & > [data-slot='drawer-description'] {
      grid-column: 1 / -1;
    }
  }

  .title {
    margin: 0;
    color: var(--drawer-title-color, var(--drawer-color, var(--color-popover-foreground)));
    font-size: var(--drawer-title-font-size, var(--text-lg));
    font-weight: var(--drawer-title-font-weight, var(--weight-semibold));
    line-height: var(--drawer-title-line-height, var(--line-height-text-lg));
  }

  .description {
    margin: 0;
    color: var(--drawer-description-color, var(--color-muted-foreground));
    font-size: var(--drawer-description-font-size, var(--text-md));
    line-height: var(--drawer-description-line-height, var(--line-height-text-md));
  }

  .body {
    min-height: 0;
    flex: 1;
    overflow: hidden;
    margin-top: var(--drawer-body-margin-top, var(--spacing-4));
    font-size: var(--drawer-body-font-size, var(--text-md));
    line-height: var(--drawer-body-line-height, var(--line-height-text-md));
  }

  .footer {
    display: flex;
    justify-content: flex-end;
    gap: var(--drawer-footer-gap, var(--spacing-2));
    margin-top: var(--drawer-footer-margin-top, var(--spacing-6));
  }

  .closeIcon {
    --close-button-size: var(--drawer-close-icon-size, 1.75rem);
    --close-button-radius: var(--drawer-close-icon-radius, var(--radius-md));
    --close-button-color: var(
      --drawer-close-icon-color,
      var(--drawer-description-color, var(--color-muted-foreground))
    );
    --close-button-color-hover: var(
      --drawer-close-icon-color-hover,
      var(--drawer-close-icon-color, var(--drawer-color, var(--color-popover-foreground)))
    );
    --close-button-bg: var(--drawer-close-icon-bg, transparent);
    --close-button-bg-hover: var(--drawer-close-icon-bg-hover, var(--color-accent));
    --close-button-focus-ring-color: var(
      --drawer-close-icon-focus-ring-color,
      var(--drawer-focus-ring-color, var(--color-ring))
    );
    --close-button-icon-size: var(--drawer-close-icon-glyph-size, 0.75rem);
    min-height: auto;
    padding: 0;
    border: 0;
  }
}
